import { closeStudio } from "../agentSessionChannel.js";
import { getConfig, hasCredentials } from "../config.js";
const args = process.argv.slice(2);
const sessionId = args[0];
const message = args[1];
if (!sessionId) {
    console.error("Usage: closeStudio <sessionId> [message]");
    process.exit(1);
}
if (!hasCredentials()) {
    console.error("Not authenticated.");
    process.exit(1);
}
const config = getConfig();
if (!config.apiKey) {
    console.error("No API key configured.");
    process.exit(1);
}
await closeStudio({ serviceUrl: config.serviceUrl, apiKey: config.apiKey, sessionId }, message);
process.exit(0);
